351		if err != nil {
352			return fmt.Errorf("insert payment event: %w", err)
353		}
354		if !isNew {
355			return tx.Commit(ctx)
356		}
357	
358		sub, err := s.repo.GetSubscriptionByHyperswitchID(ctx, tx, paymentID)
359		if err != nil {
360			return fmt.Errorf("get subscription by hyperswitch id: %w", err)
361		}
