package handler

import (
    "context"
    "net/http"

    "github.com/gin-gonic/gin"

    "github.com/ravencloak-org/Raven/pkg/apierror"
)

// Provisioner is the interface the handler depends on.
type Provisioner interface {
    ProvisionRealm(ctx context.Context, realm string) error
}

// ProvisionerHandler handles internal realm provisioning requests.
type ProvisionerHandler struct {
    svc        Provisioner
    internalKey string
}

// NewProvisionerHandler creates a ProvisionerHandler.
func NewProvisionerHandler(svc Provisioner, internalKey string) *ProvisionerHandler {
    return &ProvisionerHandler{svc: svc, internalKey: internalKey}
}

type provisionRealmRequest struct {
    Realm string `json:"realm" binding:"required,min=2,max=64"`
}

// ProvisionRealm handles POST /internal/provision-realm.
// Protected by X-Internal-Key header (static secret).
func (h *ProvisionerHandler) ProvisionRealm(c *gin.Context) {
    if c.GetHeader("X-Internal-Key") != h.internalKey {
        _ = c.Error(apierror.NewUnauthorized("invalid internal key"))
        c.Abort()
        return
    }

    var req provisionRealmRequest
    if err := c.ShouldBindJSON(&req); err != nil {
        _ = c.Error(apierror.NewBadRequest(err.Error()))
        c.Abort()
        return
    }

    if err := h.svc.ProvisionRealm(c.Request.Context(), req.Realm); err != nil {
        _ = c.Error(apierror.NewInternal(err.Error()))
        c.Abort()
        return
    }

    c.JSON(http.StatusOK, gin.H{"realm": req.Realm, "status": "provisioned"})
}
```

