```go
package keycloak

import (
    "bytes"
    "context"
    "encoding/json"
    "fmt"
    "io"
    "net/http"
    "net/url"
    "strings"
)

// AdminClient calls the Keycloak Admin REST API.
type AdminClient struct {
    baseURL      string // e.g. "http://keycloak:8080"
    adminRealm   string // realm that holds the admin service account, typically "master"
    clientID     string
    clientSecret string
    http         *http.Client
}

// NewAdminClient creates a new Keycloak admin REST client.
func NewAdminClient(baseURL, adminRealm, clientID, clientSecret string, httpClient *http.Client) *AdminClient {
    if httpClient == nil {
        httpClient = http.DefaultClient
    }
    return &AdminClient{
        baseURL:      strings.TrimRight(baseURL, "/"),
        adminRealm:   adminRealm,
        clientID:     clientID,
        clientSecret: clientSecret,
        http:         httpClient,
    }
}

// ImportRealm POSTs a full realm JSON to Keycloak Admin API.
// Returns nil if the realm is created (201) or already exists (409).
func (c *AdminClient) ImportRealm(ctx context.Context, realmJSON []byte) error {
    token, err := c.clientCredentialsToken(ctx)
    if err != nil {
        return fmt.Errorf("keycloak.AdminClient.ImportRealm: obtain token: %w", err)
    }

    req, err := http.NewRequestWithContext(ctx, http.MethodPost,
        c.baseURL+"/admin/realms", bytes.NewReader(realmJSON))
    if err != nil {
        return fmt.Errorf("keycloak.AdminClient.ImportRealm: build request: %w", err)
    }
    req.Header.Set("Content-Type", "application/json")
    req.Header.Set("Authorization", "Bearer "+token)

    resp, err := c.http.Do(req)
    if err != nil {
        return fmt.Errorf("keycloak.AdminClient.ImportRealm: HTTP: %w", err)
    }
    defer resp.Body.Close()
    _, _ = io.Copy(io.Discard, resp.Body)

    if resp.StatusCode == http.StatusCreated || resp.StatusCode == http.StatusConflict {
        return nil // 201 = created, 409 = already exists (idempotent)
    }
    return fmt.Errorf("keycloak.AdminClient.ImportRealm: unexpected status %d", resp.StatusCode)
}

// clientCredentialsToken fetches a Bearer token using the client_credentials grant.
func (c *AdminClient) clientCredentialsToken(ctx context.Context) (string, error) {
    tokenURL := fmt.Sprintf("%s/realms/%s/protocol/openid-connect/token", c.baseURL, c.adminRealm)
    form := url.Values{
        "grant_type":    {"client_credentials"},
        "client_id":     {c.clientID},
        "client_secret": {c.clientSecret},
    }
    req, err := http.NewRequestWithContext(ctx, http.MethodPost, tokenURL,
        strings.NewReader(form.Encode()))
    if err != nil {
        return "", err
    }
    req.Header.Set("Content-Type", "application/x-www-form-urlencoded")

    resp, err := c.http.Do(req)
    if err != nil {
        return "", err
    }
    defer resp.Body.Close()

    if resp.StatusCode != http.StatusOK {
        return "", fmt.Errorf("token endpoint returned %d", resp.StatusCode)
    }
    var payload struct {
        AccessToken string `json:"access_token"`
    }
    if err := json.NewDecoder(resp.Body).Decode(&payload); err != nil {
        return "", err
    }
    return payload.AccessToken, nil
}
```

