// ProvisionRealm imports the realm template into Keycloak.
// The realm name in the template is replaced with the org slug.
// Idempotent: calling this when the realm already exists is a no-op.
func (s *provisionerServiceImpl) ProvisionRealm(ctx context.Context, realmName string) error {
    // Replace realm name in template
    var payload map[string]any
    if err := json.Unmarshal(realmTemplate, &payload); err != nil {
        return fmt.Errorf("ProvisionerService.ProvisionRealm: parse template: %w", err)
    }
    payload["realm"] = realmName
    payload["displayName"] = realmName

    modified, err := json.Marshal(payload)
    if err != nil {
        return fmt.Errorf("ProvisionerService.ProvisionRealm: marshal: %w", err)
    }

    if err := s.kc.ImportRealm(ctx, bytes.NewReader(modified).(*bytes.Reader)); err != nil {
        return fmt.Errorf("ProvisionerService.ProvisionRealm: %w", err)
    }
    return nil
}
