```typescript
import { computed, ref } from 'vue'
import { useAuthStore } from '../stores/auth'

const STORAGE_KEY_PREFIX = 'raven_onboarding_completed_'

export function useOnboarding() {
  const auth = useAuthStore()

  const storageKey = computed(() =>
    auth.user ? STORAGE_KEY_PREFIX + auth.user.id : null
  )

  const isCompleted = computed(() => {
    if (!storageKey.value) return false
    return localStorage.getItem(storageKey.value) === 'true'
  })

  function markCompleted() {
    if (storageKey.value) {
      localStorage.setItem(storageKey.value, 'true')
    }
  }

  function reset() {
    if (storageKey.value) {
      localStorage.removeItem(storageKey.value)
    }
  }

  return { isCompleted, markCompleted, reset }
}
```

