    <div class="flex justify-between text-sm">
      <span class="text-gray-700 dark:text-gray-300 font-medium">{{ label }}</span>
      <span class="text-gray-500 dark:text-gray-400">
        {{ used }}{{ unit ? ` ${unit}` : '' }} / {{ displayLimit }}{{ limit > 0 && unit ? ` ${unit}` : '' }}
