async () => {
  const zoneId = "29ab17874953f5c8538f67928e3bc617";
  const tunnelCname = "f8371625-0249-4097-88be-9cf1df34db4a.cfargotunnel.com";

  // Get all records to find IDs for the broken A records
  const records = await cloudflare.request({ method: "GET", path: `/zones/${zoneId}/dns_records`, query: { per_page: "100" } });

  // Delete the two broken A records for ravencloak.org
  const aRecords = records.result.filter(r => r.name === "ravencloak.org" && r.type === "A");
  const deleteResults = await Promise.all(aRecords.map(r =>
    cloudflare.request({ method: "DELETE", path: `/zones/${zoneId}/dns_records/${r.id}` })
  ));

  // Add app.ravencloak.org → tunnel
  const addApp = await cloudflare.request({
    method: "POST",
    path: `/zones/${zoneId}/dns_records`,
    body: { type: "CNAME", name: "app", content: tunnelCname, proxied: true, ttl: 1 }
  });

  // Add ravencloak.org → tunnel (CNAME flattening at apex)
  const addRoot = await cloudflare.request({
    method: "POST",
    path: `/zones/${zoneId}/dns_records`,
    body: { type: "CNAME", name: "ravencloak.org", content: tunnelCname, proxied: true, ttl: 1 }
  });

  return {
    deleted: deleteResults.map(r => ({ success: r.success })),
    app_added: { success: addApp.success, name: addApp.result?.name },
    root_added: { success: addRoot.success, name: addRoot.result?.name }
  };
}

